  'anqing/sail': ('안칭 항구', '안후이성의 양쯔강 항구인 안칭은 \'평화로운 축제\'라는 뜻을 담고 있어요.'),
  'ganzhou/orange': ('간난 배꼽오렌지', '중국에서 가장 달콤한 배꼽오렌지가 이곳의 붉은 토양에서 자라나요.'),
  'ganzhou/house': ('객가 토루', '객가 사람들은 수 세기 동안 독특한 원형 요새 주택인 토루에서 살아왔어요.'),
  'ganzhou/pavilion': ('위구각', '송나라 시인들이 노래했던 이 정자에서는 두 강이 만나는 절경을 내려다볼 수 있어요.'),
  'ganzhou/star': ('대장정', '중국 홍군의 대장정이 바로 이 도시에서 시작되었어요.'),
  'putian/shrine': ('마조묘', '뱃사람들의 수호신인 마조 여신이 태어난 곳으로, 메이저우섬에 본당이 자리하고 있어요.'),
  'putian/lychee': ('리치 과수원', '천 년 된 리치 나무들이 가득해 이 도시는 \'리치의 고장\'이라는 별명을 얻었어요.'),
  'putian/shoe': ('신발의 도시', '전 세계 운동화의 상당수가 이곳의 공장에서 생산되고 있어요.'),
  'putian/wave': ('메이저우섬', '페리를 타고 들어갈 수 있는 이 섬은 아름다운 해변과 사원 축제로 유명해요.'),
  'mudanjiang/snow': ('중국 설향', '겨울이면 두꺼운 눈이 쌓여 동화 속 마을 같은 풍경을 자아내는 곳이에요.'),
  'mudanjiang/lake': ('징포호', '화산 활동으로 생긴 호수로, 겨울에도 웅장한 댜오수이러우 폭포를 볼 수 있어요.'),
  'mudanjiang/tiger': ('시베리아 호랑이 공원', '세계에서 가장 큰 규모를 자랑하는 시베리아 호랑이 보호구역 중 하나예요.'),
  'mudanjiang/ski': ('스키 시즌', '긴 겨울 동안 눈이 풍부하게 내려 스키어들에게 인기 있는 명소예요.'),
  'changzhou/dino': ('공룡원', '중국에서 가장 유명한 공룡 테마파크로, 가족 단위 여행객에게 인기가 많아요.'),
  'changzhou/pagoda': ('톈닝사 탑', '높이 153미터에 달하는 세계에서 가장 높은 탑이 도심에 우뚝 솟아 있어요.'),
  'changzhou/comb': ('빗 공예', '천 년의 역사를 지닌 창저우의 빗은 과거에 궁중 선물로 쓰일 만큼 귀했어요.'),
  'changzhou/canal': ('대운하', '운하를 따라 걸으며 옛 거리의 정취와 화려한 야경을 즐길 수 있어요.'),
  'shaoxing/wine': ('사오싱주', '중국 요리에 빠지지 않는 유명한 황주가 수천 년 동안 이곳에서 빚어져 왔어요.'),
  'shaoxing/bridge': ('석교', '운하가 발달한 사오싱에는 수백 개의 고풍스러운 아치형 돌다리가 남아 있어요.'),
  'shaoxing/pen': ('서예의 성지', '서예가 왕희지의 난정서가 탄생한 이곳은 서예를 공부하는 사람들에게 성지와 같아요.'),
  'shaoxing/boat': ('우펑선', '발로 노를 저어 움직이는 검은 지붕의 우펑선은 운하를 여행하는 가장 고전적인 방법이에요.'),
  'bengbu/shell': ('진주의 항구', '지명 자체가 \'조개 부두\'라는 뜻으로, 예로부터 화이허강의 진주로 유명했던 곳이에요.'),
  'bengbu/train': ('철도 요충지', '남북을 잇는 철도 노선이 화이허를 건너는 지점으로, 벵부라는 도시는 이 역을 중심으로 발전했습니다.'),
  'bengbu/river': ('화이허', '중국의 남북을 가르는 지리적 경계인 화이허가 이 도시를 유유히 흐르고 있습니다.'),
  'bengbu/blossom': ('봄꽃 축제', '매년 봄이 되면 강변 공원마다 화사한 꽃들이 만개해 아름다운 봄꽃 축제가 열립니다.'),
  'jiujiang/mountain': ('루산', '유네스코 세계유산으로 등재된 루산은 안개 낀 절경으로 수많은 시인과 화가들에게 영감을 주었습니다.'),
  'jiujiang/tea': ('윈우차', '루산의 비탈에서 재배되는 윈우차는 중국에서 가장 섬세하고 향이 좋은 차 중 하나로 꼽힙니다.'),
  'jiujiang/lake': ('포양호', '중국 최대의 담수호인 포양호는 겨울철이 되면 수천 마리의 두루미가 찾아오는 철새들의 낙원입니다.'),
  'jiujiang/scroll': ('시의 도시', '백거이와 소식 같은 대문호들이 이곳 강변을 거닐며 주옥같은 시를 남겼습니다.'),
  'quanzhou/ship': ('해상 실크로드', '마르코 폴로가 \'자이툰\'이라 불렀던 이곳은 중세 시대 세계 최대의 항구였으며 유네스코 세계유산으로 지정되었습니다.'),
  'quanzhou/mosque': ('칭징사', '1009년에 세워진 이 돌로 만든 이슬람 사원은 중국에서 가장 오래된 사원 중 하나입니다.'),
  'quanzhou/puppet': ('꼭두각시 인형극', '취안저우의 줄 인형극은 천 년의 역사를 자랑하는 전통 공연 예술입니다.'),
  'quanzhou/tea': ('철관음', '인근 안시 지역에서 생산되는 철관음은 세계적으로 유명한 우롱차의 일종입니다.'),
  'beijing/great-wall': ('만리장성', '중국 북부 국경을 지키기 위해 수세기에 걸쳐 쌓은 세계 최장의 성벽으로, 베이징 인근의 바다링 장성은 가장 많은 사람이 찾는 구간입니다.'),
  'beijing/temple': ('천단', '명·청 시대 황제들이 풍년을 기원하며 제사를 지내던 곳으로, 못을 사용하지 않고 지은 푸른 지붕의 건축물은 중국을 상징하는 아이콘입니다.'),
  'beijing/pagoda': ('톈닝사 탑', '요나라 시대에 세워진 13층 벽돌 탑으로, 정교한 조각과 팔각형의 몸체는 베이징의 천 년 역사를 증명하는 귀중한 유산입니다.'),
  'beijing/opera': ('경극', '노래와 대사, 무술과 곡예가 어우러진 200년 전통의 종합 예술로, 배우들의 얼굴 분장인 \'연보\'를 통해 인물의 성격을 알 수 있습니다.'),
};
